import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it.todo("should return base premium for a single sword plus processing fee");
    it.todo("should return base premium for an amulet plus processing fee");
    it.todo("should return base premium for a staff plus processing fee");
    it.todo("should return base premium for a potion plus processing fee");
  });

  describe("Quote - risk surcharges", () => {
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for a highly enchanted item (level >= 5)");
    it.todo("should add both surcharges when item is cursed and highly enchanted");
  });

  describe("Quote - customer discounts and surcharges", () => {
    it.todo("should add 10% initial assessment surcharge for first insurance");
    it.todo("should add 15% discount for each contract after the first");
    it.todo("should add 20% loyalty discount for long-standing customers (>= 2 years)");
  });

  describe("Quote - components", () => {
    it.todo("should price a single component at 25G base premium plus processing fee");
    it.todo("should apply special 60G premium for a group of 3 alike components");
  });

  describe("Claim - basic payout", () => {
    it.todo("should deduct 100G deductible from a damage claim");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
    it.todo("should fully reimburse damage to items made of dragon material");
  });
});

