type Item = { type: string; cursed?: boolean; enchantment?: number };
type Step = { op: string; items?: Item[] };
type Scenario = { customer: unknown; steps: Step[] };
type StepResult = { premium?: number; payout?: number; remainingCap?: number };
type ScenarioResult = { results: StepResult[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const PROCESSING_FEE = 5;

const calculatePremium = (item: Item | undefined, isFirstContract: boolean): number => {
  const basePremium = BASE_PREMIUM[item?.type ?? ""];
  const cursedMultiplier = item?.cursed ? 1.5 : 1;
  const enchantedMultiplier = (item?.enchantment ?? 0) >= 5 ? 1.3 : 1;
  const riskAdjusted = basePremium * cursedMultiplier * enchantedMultiplier;
  if (isFirstContract) {
    return Math.ceil(riskAdjusted * 11 / 10) + PROCESSING_FEE; // +10% surcharge, integer ratio avoids float
  }
  return Math.ceil(riskAdjusted * 85 / 100) + PROCESSING_FEE; // -15% discount, integer ratio avoids float
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFirstContract = quoteCount === 0;
      quoteCount++;
      return { premium: calculatePremium(step.items?.[0], isFirstContract) };
    }
    return {};
  });
  return { results };
};

